#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[1000];
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
        }
        int leaders[1000];
        int cnt = 0;
        int maxFromRight = arr[N-1];
        leaders[cnt++] = maxFromRight; // rightmost element
        for (int i = N-2; i >= 0; --i) {
            if (arr[i] > maxFromRight) {
                maxFromRight = arr[i];
                leaders[cnt++] = maxFromRight;
            }
        }
        // print in reverse to restore left‑to‑right order
        for (int i = cnt-1; i >= 0; --i) {
            printf("%d", leaders[i]);
            if (i) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

